#!/usr/bin/env node
/**
 * Build script for Metal Mania UI assets.
 *
 * Produces two independent bundles — editor and public — each with:
 *   • a plain (unminified) version for ?minLibs=no development use
 *   • a minified production version
 *
 * Both JS and CSS are handled by esbuild.
 *
 * Usage:
 *   node scripts/bundle.js           — full build (dev + minified)
 *   node scripts/bundle.js --watch   — watch mode, dev builds only
 *
 * Output layout under  ../src/main/content/jcr_root/apps/metal-mania/
 *
 *   js/
 *     editor/
 *       editor-bundle.js        ← dev (unminified, inline source map)
 *       editor-bundle.min.js    ← prod (minified, htmx inlined)
 *     public/
 *       public-bundle.js
 *       public-bundle.min.js
 *   css/
 *     editor/
 *       editor.css              ← dev (unminified, inline source map)
 *       editor.min.css
 *     public/
 *       public.css
 *       public.min.css
 */

'use strict';

const esbuild = require('esbuild');
const fs      = require('fs');
const path    = require('path');

// ── Paths ──────────────────────────────────────────────────────────────────

const ROOT     = path.resolve(__dirname, '..');
const JCR_BASE = path.resolve(ROOT, '../src/main/content/jcr_root/apps/metal-mania');
const JS_ROOT  = path.join(JCR_BASE, 'js');
const CSS_ROOT = path.join(JCR_BASE, 'css');
const HTMX_SRC = path.join(ROOT, 'node_modules/htmx.org/dist/htmx.js');

const BUNDLES = [
  {
    name:       'editor',
    jsEntry:    path.join(ROOT, 'src/typescript/editor.ts'),
    cssEntry:   path.join(ROOT, 'src/css/editor/editor.css'),
    jsOutDir:   path.join(JS_ROOT,  'editor'),
    cssOutDir:  path.join(CSS_ROOT, 'editor'),
    inlineHtmx: true,
  },
  {
    name:       'public',
    jsEntry:    path.join(ROOT, 'src/typescript/public.ts'),
    cssEntry:   path.join(ROOT, 'src/css/public/public.css'),
    jsOutDir:   path.join(JS_ROOT,  'public'),
    cssOutDir:  path.join(CSS_ROOT, 'public'),
    inlineHtmx: false,
  },
];

function mkdirp(dir) {
  fs.mkdirSync(dir, { recursive: true });
}

// ── Banners ────────────────────────────────────────────────────────────────

function jsBanner(name) {
  return [
    '/*!',
    ' * !! DO NOT EDIT THIS FILE DIRECTLY !!',
    ' *',
    ' * AUTO-GENERATED by the frontend build script (esbuild).',
    ` * Source entry: frontend/src/typescript/${name}.ts`,
    ' * Inline source map included — open Browser DevTools > Sources for per-file navigation.',
    ' */',
  ].join('\n');
}

function cssBanner(name) {
  return [
    '/*!',
    ' * !! DO NOT EDIT THIS FILE DIRECTLY !!',
    ' *',
    ' * AUTO-GENERATED by the frontend build script (esbuild).',
    ` * Source: frontend/src/css/${name}/`,
    ' * Inline source map included — open Browser DevTools > Sources for per-file navigation.',
    ' */',
  ].join('\n');
}

// ── Full build ─────────────────────────────────────────────────────────────

async function build() {
  console.log('Building Metal Mania UI assets…\n');

  await Promise.all(
    BUNDLES.flatMap(({ name, jsEntry, cssEntry, jsOutDir, cssOutDir, inlineHtmx }) => {
      mkdirp(jsOutDir);
      mkdirp(cssOutDir);
      const htmxBanner = inlineHtmx ? fs.readFileSync(HTMX_SRC, 'utf8') : '';

      return [
        // JS — dev (unminified, inline source map)
        esbuild.build({
          entryPoints: [jsEntry],
          bundle:      true,
          format:      'iife',
          outfile:     path.join(jsOutDir, `${name}-bundle.js`),
          minify:      false,
          sourcemap:   'inline',
          target:      'es2020',
          banner:      { js: jsBanner(name) },
        }),
        // JS — prod (minified, htmx inlined for editor)
        esbuild.build({
          entryPoints: [jsEntry],
          bundle:      true,
          format:      'iife',
          outfile:     path.join(jsOutDir, `${name}-bundle.min.js`),
          minify:      true,
          sourcemap:   false,
          target:      'es2020',
          ...(htmxBanner ? { banner: { js: htmxBanner } } : {}),
        }),
        // CSS — dev (unminified, inline source map)
        esbuild.build({
          entryPoints: [cssEntry],
          bundle:      true,
          outfile:     path.join(cssOutDir, `${name}.css`),
          minify:      false,
          sourcemap:   'inline',
          banner:      { css: cssBanner(name) },
        }),
        // CSS — prod (minified)
        esbuild.build({
          entryPoints: [cssEntry],
          bundle:      true,
          outfile:     path.join(cssOutDir, `${name}.min.css`),
          minify:      true,
          sourcemap:   false,
        }),
      ];
    })
  );

  console.log('✓ Build complete!');
}

// ── Watch mode ─────────────────────────────────────────────────────────────
// Builds only the dev (unminified) targets — use with ?minLibs=no.
// Pairs naturally with `mvn sling:fsmount` which syncs JCR content to disk;
// esbuild writes rebuilt files into the fsmounted tree so Sling picks them up
// on the next browser request with no Maven build needed.

async function watch() {
  console.log('Watching Metal Mania UI assets (dev builds only)…');
  console.log('Open pages with ?minLibs=no to load the unminified files.\n');

  const contexts = await Promise.all(
    BUNDLES.flatMap(({ name, jsEntry, cssEntry, jsOutDir, cssOutDir }) => {
      mkdirp(jsOutDir);
      mkdirp(cssOutDir);

      return [
        esbuild.context({
          entryPoints: [jsEntry],
          bundle:      true,
          format:      'iife',
          outfile:     path.join(jsOutDir, `${name}-bundle.js`),
          minify:      false,
          sourcemap:   'inline',
          target:      'es2020',
          banner:      { js: jsBanner(name) },
        }),
        esbuild.context({
          entryPoints: [cssEntry],
          bundle:      true,
          outfile:     path.join(cssOutDir, `${name}.css`),
          minify:      false,
          sourcemap:   'inline',
          banner:      { css: cssBanner(name) },
        }),
      ];
    })
  );

  await Promise.all(contexts.map((ctx) => ctx.watch()));
  console.log(`Watching ${contexts.length} targets. Ctrl+C to stop.\n`);

  process.on('SIGINT', async () => {
    console.log('\nStopping watch…');
    await Promise.all(contexts.map((ctx) => ctx.dispose()));
    process.exit(0);
  });
}

// ── Entry point ────────────────────────────────────────────────────────────

const isWatch = process.argv.includes('--watch');
(isWatch ? watch() : build()).catch((err) => {
  console.error(err);
  process.exit(1);
});
